"use client";

import { motion, useScroll, useTransform } from "motion/react";
import { useRef, type ReactNode } from "react";
import { Reveal } from "./Reveal";
import { clsx } from "@/lib/clsx";
import { DashboardMock, AiChatMock, AutomationMock } from "./mockups";

const FEATURES = [
  {
    eyebrow: "Dashboards Estratégicos",
    title: (
      <>
        Dashboards que mostram o que{" "}
        <span className="editorial font-normal accent">realmente importa.</span>
      </>
    ),
    desc: "Painéis personalizados por área e nível hierárquico, com os indicadores certos para cada decisão.",
    tags: ["Diretoria", "Financeiro", "Comercial", "Operacional"],
    mock: <DashboardMock />,
    flip: false,
  },
  {
    eyebrow: "do.thus IA",
    title: (
      <>
        <span className="editorial font-normal accent">Converse</span> com os
        dados da sua empresa.
      </>
    ),
    desc: "Gestores conversam com os dados, recebem análises e alertas — para decisões mais inteligentes, 24/7.",
    tags: ["Qual área caiu?", "Onde perco margem?", "Quem exige atenção?"],
    mock: <AiChatMock />,
    flip: true,
  },
  {
    eyebrow: "Automações",
    title: (
      <>
        Menos operacional, mais{" "}
        <span className="editorial font-normal accent">estratégico.</span>
      </>
    ),
    desc: "Relatórios, integrações e alertas que rodam sozinhos e avisam quando algo sai do plano.",
    tags: ["Sem intervenção", "Sistemas integrados", "Alertas no ponto"],
    mock: <AutomationMock />,
    flip: false,
  },
];

export function Showcase() {
  return (
    <section className="relative bg-abyss py-20 sm:py-28">
      <div className="container-do flex flex-col gap-28 sm:gap-40">
        {FEATURES.map((f) => (
          <FeatureRow key={f.eyebrow} {...f} />
        ))}
      </div>
    </section>
  );
}

function FeatureRow({
  eyebrow,
  title,
  desc,
  tags,
  mock,
  flip,
}: {
  eyebrow: string;
  title: ReactNode;
  desc: string;
  tags: string[];
  mock: ReactNode;
  flip: boolean;
}) {
  const ref = useRef<HTMLDivElement>(null);
  const { scrollYProgress } = useScroll({
    target: ref,
    offset: ["start end", "end start"],
  });
  const y = useTransform(scrollYProgress, [0, 1], [60, -60]);

  return (
    <div
      ref={ref}
      className="grid items-center gap-12 lg:grid-cols-2 lg:gap-20"
    >
      {/* texto */}
      <div className={clsx(flip && "lg:order-2")}>
        <span className="mb-5 inline-block text-xs font-semibold uppercase tracking-[0.32em] text-electric">
          {eyebrow}
        </span>
        <Reveal>
          <h3 className="text-[clamp(1.8rem,3.6vw,2.9rem)] font-semibold leading-[1.05] text-snow">
            {title}
          </h3>
        </Reveal>
        <Reveal delay={0.1}>
          <p className="mt-6 max-w-md text-lg leading-relaxed text-text-dim">
            {desc}
          </p>
        </Reveal>
        <Reveal delay={0.18}>
          <div className="mt-7 flex flex-wrap gap-2.5">
            {tags.map((t) => (
              <span
                key={t}
                className="rounded-full border border-line bg-surface/50 px-4 py-1.5 text-sm font-medium text-text-dim"
              >
                {t}
              </span>
            ))}
          </div>
        </Reveal>
      </div>

      {/* mockup com parallax */}
      <motion.div
        style={{ y }}
        className={clsx(
          "flex justify-center",
          flip ? "lg:order-1 lg:justify-start" : "lg:justify-end"
        )}
      >
        <div className="w-full max-w-md">{mock}</div>
      </motion.div>
    </div>
  );
}
